var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"응? 서윤 씨? 여기서 뭘 하고 있어요?","JPN":"あれ、シズカさん？　ここで何をしてるんですか？","ENG":"Huh? Seo Yoon? What are you doing here?","TWN":"嗯？徐芸小姐？妳在這裡做什麼？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아...... 하하하.","JPN":"あ……ハハハ。","ENG":"Oh... Hahaha...","TWN":"啊……哈哈哈。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"사, 상황이 궁금해서요. 뭐라도 알아보려고 찾아보던 중이었어요.","JPN":"じょ、状況が気になって。どんなことでもいいから探ってみようとしていたところでした。","ENG":"I-I was curious about how things were going. Just trying to see if I can find out anything about the current situation.","TWN":"我、我只是好奇情況怎麼樣了，所以想要調查看看。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"상황요? 엉망이죠, 뭐.","JPN":"状況ですか？　まあ、最悪ですよ。","ENG":"The situation? It’s a mess, basically.","TWN":"情況嗎？就亂七八糟的啊，唉。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"랜덤 좌표 다이브라니, 이런 자살특공 같은 짓을 할 줄 누가 알았겠어요?","JPN":"ランダム座標ダイブだなんて、あんな自殺行為をするとは。","ENG":"I mean, diving with random coordinates? Who knew we’d end up on a suicide mission like this?","TWN":"躍入到隨機座標，天知道我們竟然會做這種自殺式的行為？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"역시 엄마 말대로 얌전히 공무원 시험 준비나 할 걸 그랬나 봐요.","JPN":"やっぱり母さんの言うとおり、おとなしく\\n公務員試験の準備でもした方がよかったのかも。","ENG":"I should've just listened to mom and gone to dental school.","TWN":"早知道我就聽媽媽的話，乖乖準備公務員考試了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"살아서 돌아가면 사표 쓰고 카페 아르바이트 자리라도 알아봐야 하나......","JPN":"もし生還できたら、ここは辞めてカフェのバイトでも探そうかな……","ENG":"If I ever make it back alive, I’m going to quit and look for a job as a barista or something...","TWN":"要是能活著回去的話我就辭職，就算是去咖啡館打工也可以……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그래도 설마 죽기야 하겠어요?","JPN":"でもまあ、まさか死ぬことはないんじゃないですか？","ENG":"Aw, I’m sure we’ll make it out alive.","TWN":"那萬一死掉了呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"글쎄요? 어이~ 클로에~!","JPN":"どうでしょうね……ねえークロエ～？","ENG":"I wouldn’t be so sure about that... Hey, Chloe!","TWN":"這個嘛？喂～克洛伊～！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어때, 살아 나갈 수 있을 것 같아?","JPN":"どう？　生きて帰れそう？","ENG":"What do you think? Can we make it out alive?","TWN":"怎麼樣，妳覺得我們能活著回去嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"무사히 돌아간다, 못 돌아간다, 무사히 돌아간다, 못 돌아간다......","JPN":"無事に帰れる、帰れない、無事に帰れる、帰れない……","ENG":"We’ll make it, we won’t, we’ll make it, we won’t...","TWN":"回得去，回不去，回得去，回不去……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"......못 돌아간다.","JPN":"……帰れない。","ENG":"...We won’t.","TWN":"……回不去。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......망했네?","JPN":"……ハイ、終了。","ENG":"Oh, we're screwed.","TWN":"……完了？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"에, 에잇! 이건 전부 레나 양이 쓸데없이 말을 걸어서 요정님께 부정을 탔기 때문입니다!","JPN":"も、もうっ！　レナがいきなり声をかけてきたりするから、妖精様のお怒りを買ったんです！","ENG":"D-dang it! This is all because you’ve angered the fairy godmother by talking to me while I was communing with her!","TWN":"討、討厭！都怪蕾娜小姐說那些有的沒的，害妖精大人不高興了！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"이건 무효에요! 무효! 다시 합니다!","JPN":"だから、これは無効です、無効！　やり直し！","ENG":"This doesn’t count! Nope! Do-over!","TWN":"這次無效！無效！再來算一次！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그래? 순결한 처녀가 말을 걸었는데 부정을 타다니. 그 요정님 취향 한 번 독특하시네.","JPN":"そうなの？　純潔の乙女に話しかけられたのに、お怒りになるなんて。\\n妖精様も不思議な方だわ～。","ENG":"Oh, really? But I’m just an innocent girl worried about her well being. I didn’t realize your fairy godmother was so mean.","TWN":"是嗎？竟然會因為被純潔少女搭話感到不高興，這個妖精大人的喜好還真是獨特啊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그것 봐요! 정령님이 노하신 거라고요! 이렇게 계시를......!","JPN":"ほら！精霊様も怒ってるんですよ！　こうやって啓示を……！","ENG":"See? The spirit is angry! He’s given us this omen!","TWN":"妳看！精靈大人發怒了！這是神的指示……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아니야! 이건 비상 경계 신호라고!","JPN":"違うよ！　これは非常警戒信号だよ！","ENG":"No! That’s the emergency alert signal!","TWN":"才不是！這是緊急戒備信號！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};